#include <bits/stdc++.h>
using namespace std;
int a[100101];
long long ans = 0, n, m, l = 0, r = 100000001, mid;
long long cmp(long long x) {
    ans=0;
	for (int i = 0; i < n; i++) {
		ans += a[i] / x;
	}
	return ans >= m;
}
int main() {

	cin >> n >> m;
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}
	while (l + 1 < r) {
		mid = (l + r) / 2;
		if(cmp(mid)){
			l=mid;
		}else{
			r=mid;
		}

	}
	cout << l;

	return 0;
}
